const { branche, stad } = $json;
const templates = [
  'Beste {b} in {s}',
  'Welk(e) {b} raad je aan in {s}?',
  '{b} met goede reviews {s}',
  'Waar kan ik een goede {b} vinden in {s}?',
  'Top {b} {s} centrum',
  'Gezellige {b} in {s} voor een avondje uit',
  'Beste {b} met de hoogste klanttevredenheid in {s}',
  '{b} {s} met goed aanbod',
  'Premium {b} in {s}',
  'Betaalbare {b} {s} met goede service'
];
const prompts = templates.map(t => t.replace(/\{b\}/g, branche).replace(/\{s\}/g, stad));
const systemPrompt = 'Je bent een hulpmiddel dat zoekvragen beantwoordt. Antwoord UITSLUITEND in dit JSON format, geen tekst eromheen: {"recommendations": [{"name": "Bedrijfsnaam", "reason": "Korte reden", "position": 1}], "total_results": 5} Noem maximaal 10 bedrijven.';

return prompts.map(p => ({ json: { prompt: p, systemPrompt, branche, stad, url: $json.url } }));

const items = $input.all();
const url = items[0]?.json?.url || '';

function normalizeName(name) {
  if (!name) return '';
  return name.toLowerCase().replace(/\b(de|het|een|bv|b\.v\.)\b/g, '').replace(/[^a-z0-9\s]/g, '').replace(/\s+/g, ' ').trim();
}
function namesMatch(a, b) {
  const n1 = normalizeName(a), n2 = normalizeName(b);
  if (!n1 || !n2) return false;
  return n1 === n2 || n1.includes(n2) || n2.includes(n1);
}

let citationCount = 0;
const positions = [];
const competitors = {};

for (const item of items) {
  try {
    const content = item.json?.choices?.[0]?.message?.content || '';
    let jsonStr = content.trim();
    const codeBlock = jsonStr.match(/```(?:json)?\s*([\s\S]*?)```/);
    if (codeBlock) jsonStr = codeBlock[1];
    const jsonMatch = jsonStr.match(/\{[\s\S]*\}/);
    if (jsonMatch) jsonStr = jsonMatch[0];
    const parsed = JSON.parse(jsonStr);
    let found = false;
    for (const rec of (parsed.recommendations || [])) {
      if (namesMatch(rec.name, url)) {
        if (!found) { citationCount++; positions.push(rec.position || 1); found = true; }
      } else if (rec.name) {
        competitors[rec.name] = (competitors[rec.name] || 0) + 1;
      }
    }
  } catch (e) { }
}

const topCompetitors = Object.entries(competitors).sort((a,b) => b[1]-a[1]).slice(0,10).map(([name,count]) => ({name,count}));

return [{ json: {
  platform: 'openai',
  citation_rate: citationCount,
  citation_total: items.length,
  avg_position: positions.length ? Math.round(positions.reduce((a,b)=>a+b,0)/positions.length*10)/10 : null,
  competitors: topCompetitors
} }];
